      "main.py": {
        "name": "main.py",
        "content": "# 💬 감성 분석기 프로젝트\n# 우측 가이드 패널에서 단계를 클릭해 각 STEP으로 이동할 수 있어요.\n\n\n## STEP 1: 긍정/부정 키워드 사전 구축\npositive_words = {\n    \"좋다\", \"좋아\", \"좋은\", \"훌륭\", \"최고\", \"멋진\", \"멋지다\",\n    \"행복\", \"기쁘다\", \"기쁜\", \"만족\", \"추천\", \"사랑\", \"감동\",\n    \"재미있다\", \"재밌다\", \"재밌는\", \"유익\", \"편리\", \"깨끗\",\n    \"친절\", \"맛있다\", \"맛있는\", \"완벽\", \"대박\", \"굿\", \"짱\",\n    \"감사\", \"예쁜\", \"예쁘다\", \"뛰어난\", \"우수\", \"즐거운\",\n}\n\nnegative_words = {\n    \"나쁘다\", \"나쁜\", \"싫다\", \"싫은\", \"별로\", \"최악\", \"짜증\",\n    \"실망\", \"불만\", \"불편\", \"화나다\", \"화난\", \"슬프다\", \"슬픈\",\n    \"지루하다\", \"지루한\", \"아쉽다\", \"아쉬운\", \"힘들다\", \"어렵다\",\n    \"비싸다\", \"비싼\", \"느리다\", \"느린\", \"더럽다\", \"불친절\",\n    \"맛없다\", \"맛없는\", \"후회\", \"망\", \"거짓\", \"부족\",\n}\n\n# 부정어 목록 (뒤에 오는 감성을 반전시킴)\nnegation_words = {\"안\", \"못\", \"없다\", \"없는\", \"아니\", \"절대\"}\n\nprint(f\"긍정 키워드: {len(positive_words)}개\")\nprint(f\"부정 키워드: {len(negative_words)}개\")\nprint(f\"부정어: {len(negation_words)}개\")\n\n\n## STEP 2: 텍스트 전처리 (토큰화)\ndef tokenize(text):\n    \"\"\"텍스트를 단어 단위로 분리합니다.\"\"\"\n    # 간단한 공백 기반 토큰화\n    tokens = text.strip().split()\n    return tokens\n\n\n## STEP 3: 감성 점수 계산 (부정어 처리 포함)\ndef analyze_sentiment(text):\n    \"\"\"텍스트의 감성 점수를 계산합니다.\n    양수: 긍정, 음수: 부정, 0: 중립\n    \"\"\"\n    tokens = tokenize(text)\n    score = 0\n    details = []\n\n    for i, token in enumerate(tokens):\n        # 이전 단어가 부정어인지 확인\n        is_negated = i > 0 and tokens[i - 1] in negation_words\n\n        if token in positive_words:\n            if is_negated:\n                score -= 1  # 부정어 + 긍정 = 부정\n                details.append(f\"  '{tokens[i-1]} {token}' → -1 (부정어 반전)\")\n            else:\n                score += 1\n                details.append(f\"  '{token}' → +1 (긍정)\")\n        elif token in negative_words:\n            if is_negated:\n                score += 1  # 부정어 + 부정 = 긍정\n                details.append(f\"  '{tokens[i-1]} {token}' → +1 (부정어 반전)\")\n            else:\n                score -= 1\n                details.append(f\"  '{token}' → -1 (부정)\")\n\n    # 감성 레이블 결정\n    if score > 0:\n        label = \"긍정 😊\"\n    elif score < 0:\n        label = \"부정 😞\"\n    else:\n        label = \"중립 😐\"\n\n    return {\"text\": text, \"score\": score, \"label\": label, \"details\": details}\n\n\n## STEP 4: 부정어 처리 확인 (위 analyze_sentiment 함수에 이미 포함)\ndef print_result(result):\n    \"\"\"분석 결과를 보기 좋게 출력합니다.\"\"\"\n    print(f'\\n📝 \"{result[\"text\"]}\"')\n    print(f\"   결과: {result['label']} (점수: {result['score']:+d})\")\n    if result[\"details\"]:\n        for d in result[\"details\"]:\n            print(f\"   {d}\")\n\n\n## STEP 5: 테스트 문장으로 분석\ntest_sentences = [\n    (\"이 영화 정말 재미있다 최고\", \"긍정\"),\n    (\"음식이 맛있고 서비스도 친절 추천\", \"긍정\"),\n    (\"완전 별로 실망 다시 안 간다\", \"부정\"),\n    (\"가격이 비싸다 맛없다 후회\", \"부정\"),\n    (\"안 좋은 경험이었다\", \"부정\"),\n    (\"나쁘다고 할 수 없는 맛\", \"긍정\"),\n    (\"그냥 보통이었다\", \"중립\"),\n    (\"감동 받았고 행복 했다\", \"긍정\"),\n    (\"지루하다 재미없다 시간 낭비\", \"부정\"),\n    (\"친절 하고 깨끗 하지만 비싸다\", \"긍정\"),\n]\n\nprint(\"\\n\" + \"=\" * 50)\nprint(\"       감성 분석 테스트 결과\")\nprint(\"=\" * 50)\n\ncorrect = 0\ntotal = len(test_sentences)\n\nfor text, expected in test_sentences:\n    result = analyze_sentiment(text)\n    print_result(result)\n\n    # 예측 레이블 추출 (이모지 제거)\n    predicted = result[\"label\"].split()[0]\n    is_correct = predicted == expected\n    if is_correct:\n        correct += 1\n    status = \"✅\" if is_correct else \"❌\"\n    print(f\"   정답: {expected} {status}\")\n\n\n## STEP 6: 정확도 평가\nprint(\"\\n\" + \"=\" * 50)\nprint(f\"  정확도: {correct}/{total} ({correct/total:.0%})\")\nprint(\"=\" * 50)\n\n# 사용자 입력 테스트\nprint(\"\\n=== 추가 분석 테스트 ===\")\ncustom_texts = [\n    \"오늘 날씨도 좋은 멋진 하루\",\n    \"이 제품은 별로 추천 안 한다\",\n    \"감사합니다 만족 합니다 대박\",\n]\nfor text in custom_texts:\n    result = analyze_sentiment(text)\n    print_result(result)\n",
        "language": "python"
      }
